const text = $input.first().json.content[0].text;
const cleaned = text.replace(/```json|```/g, '').trim();
const parsed = JSON.parse(cleaned);

return [{
  json: {
    detected_size: parsed.detected_size,
    orientation: parsed.orientation,
    is_color: parsed.is_color,
    num_pages: parsed.num_pages,
    print_type: parsed.print_type,
    width_mm: parsed.width_mm,
    height_mm: parsed.height_mm
  }
}];

// מנקה סימני Markdown אם קיימים והופך ל-JSON אמיתי
let rawOutput = $json.output || $json.text;
const cleanJson = JSON.parse(rawOutput.replace(/```json|```/g, "").trim());

return {
  intents: cleanJson.intents, // רשימת הסוכנים (מערך)
  is_new: cleanJson.is_new,
  context: cleanJson.context_summary
};

